class MainActivity : ComponentActivity() {
    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        enableEdgeToEdge()
        setContent {
            CPASongsTheme {
                CPAMainApp()
            }
        }
    }
}

// App Navigation
enum class Screen {
    HOME, SONG_BOOK, BIBLE_READER, PRAYER_REQUESTS
}

@Composable
fun CPAMainApp() {
    var currentScreen by remember { mutableStateOf(Screen.HOME) }

    BackHandler(enabled = currentScreen != Screen.HOME) {
        currentScreen = Screen.HOME
    }

    AnimatedContent(
        targetState = currentScreen,
        transitionSpec = {
            val goingForward = targetState != Screen.HOME
            if (goingForward) {
                slideInHorizontally { it } togetherWith slideOutHorizontally { -it }
            } else {
                slideInHorizontally { -it } togetherWith slideOutHorizontally { it }
            }
        },
        label = "screenTransition"
    ) { screen ->
        when (screen) {
            Screen.HOME -> HomeMenuScreen(
                onNavigate = { currentScreen = it }
            )
            Screen.SONG_BOOK -> SongBookApp(
                onBack = { currentScreen = Screen.HOME }
            )
            Screen.BIBLE_READER -> BibleScreen(
                onBack = { currentScreen = Screen.HOME }
            )
            Screen.PRAYER_REQUESTS -> ComingSoonScreen(
                title = "Prayer Requests",
                onBack = { currentScreen = Screen.HOME }
            )
        }
    }
}

@Composable
fun HomeMenuScreen(onNavigate: (Screen) -> Unit) {
    val configuration = LocalConfiguration.current
    val isTablet = configuration.screenWidthDp >= 600

    Scaffold(
        containerColor = MaterialTheme.colorScheme.background
    ) { padding ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding),
            horizontalAlignment = Alignment.CenterHorizontally
        ) {
            Spacer(modifier = Modifier.height(if (isTablet) 80.dp else 48.dp))

            // App Icon
            Box(
                modifier = Modifier
                    .size(if (isTablet) 100.dp else 80.dp)
                    .clip(RoundedCornerShape(20.dp))
                    .background(Color.White),
                contentAlignment = Alignment.Center
            ) {
                Image(
                    painter = painterResource(id = R.mipmap.ic_launcher_foreground),
                    contentDescription = "CPA Logo",
                    modifier = Modifier.fillMaxSize()
                )
            }

            Spacer(modifier = Modifier.height(20.dp))

            // Organization Name
            Text(
                "Calvary Pentecostal Assemblies of Pakistan",
                style = MaterialTheme.typography.titleLarge.copy(
                    lineHeight = 30.sp
                ),
                fontWeight = FontWeight.Bold,
                color = MaterialTheme.colorScheme.onBackground,
                textAlign = TextAlign.Center,
                modifier = Modifier.padding(horizontal = 24.dp)
            )

            Spacer(modifier = Modifier.height(12.dp))

            // Bible Verse
            Text(
                "\"Go ye into all the world, and preach the gospel.\"",
                style = MaterialTheme.typography.bodyMedium.copy(
                    lineHeight = 22.sp
                ),
                fontWeight = FontWeight.Medium,
                color = MaterialTheme.colorScheme.primary,
                textAlign = TextAlign.Center,
                modifier = Modifier.padding(horizontal = 32.dp)
            )

            Spacer(modifier = Modifier.height(8.dp))

            // Mission Statement
            Text(
                "Spreading faith, hope, and love through worship, ministry, and community service across Pakistan and beyond.",
                style = MaterialTheme.typography.bodySmall.copy(
                    lineHeight = 20.sp
                ),
                color = MaterialTheme.colorScheme.onSurfaceVariant,
                textAlign = TextAlign.Center,
                modifier = Modifier.padding(horizontal = 32.dp)
            )

            Spacer(modifier = Modifier.height(24.dp))

            // Menu Items
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(horizontal = if (isTablet) 100.dp else 20.dp),
                verticalArrangement = Arrangement.spacedBy(if (isTablet) 14.dp else 12.dp)
            ) {
                AnimatedMenuItem(
                    delay = 0,
                    content = {
                        MenuItemCard(
                            icon = Icons.Rounded.MusicNote,
                            title = "Song Book",
                            onClick = { onNavigate(Screen.SONG_BOOK) }
                        )
                    }
                )
                AnimatedMenuItem(
                    delay = 100,
                    content = {
                        MenuItemCard(
                            icon = Icons.Rounded.Book,
                            title = "Bible",
                            onClick = { onNavigate(Screen.BIBLE_READER) }
                        )
                    }
                )
                AnimatedMenuItem(
                    delay = 200,
                    content = {
                        MenuItemCard(
                            icon = Icons.Rounded.Person,
                            title = "Prayer Requests",
                            onClick = { onNavigate(Screen.PRAYER_REQUESTS) }
                        )
                    }
                )
            }

            Spacer(modifier = Modifier.height(24.dp))
        }
    }
}

@Composable
fun AnimatedMenuItem(
    delay: Int,
    content: @Composable () -> Unit
) {
    content()
}

@Composable
fun MenuItemCard(
    icon: ImageVector,
    title: String,
    onClick: () -> Unit
) {
    Card(
        onClick = onClick,
        modifier = Modifier
            .fillMaxWidth(),
        shape = RoundedCornerShape(16.dp),
        colors = CardDefaults.cardColors(
            containerColor = MaterialTheme.colorScheme.surface
        ),
        elevation = CardDefaults.cardElevation(defaultElevation = 2.dp)
    ) {
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(horizontal = 18.dp, vertical = 16.dp),
            verticalAlignment = Alignment.CenterVertically
        ) {
            // Icon box with gradient background
            Box(
                modifier = Modifier
                    .size(52.dp)
                    .clip(RoundedCornerShape(14.dp))
                    .background(
                        brush = Brush.linearGradient(
                            colors = listOf(
                                Color(0xFF4A90D9),  // Light blue
                                Color(0xFF1E3A5F)   // Dark blue
                            )
                        )
                    ),
                contentAlignment = Alignment.Center
            ) {
                Icon(
                    imageVector = icon,
                    contentDescription = title,
                    tint = Color.White,
                    modifier = Modifier.size(26.dp)
                )
            }
            Spacer(modifier = Modifier.width(18.dp))
            Text(
                text = title,
                style = MaterialTheme.typography.titleMedium,
                fontWeight = FontWeight.SemiBold,
                color = MaterialTheme.colorScheme.onSurface
            )
        }
    }
}

