// ============ BIBLE READER IMPLEMENTATION ============

// Bible Language
enum class BibleLanguage(val code: String, val displayName: String) {
    ENGLISH("en", "English"),
    URDU("ur", "اُردُو")
}

// Bible Data Classes
data class BibleBook(
    val id: Int,
    val name: String,
    val nameUrdu: String,
    val testament: String,
    val chapters: Int
) {
    fun getDisplayName(language: BibleLanguage): String {
        return if (language == BibleLanguage.URDU) nameUrdu else name
    }
}

data class BibleVerse(
    val verse: Int,
    val text: String
)

data class BibleChapter(
    val book: String,
    val chapter: Int,
    val verses: List<BibleVerse>
)

// Bible Data Storage - Offline First
object BibleStorage {
    private var cachedBooks: Map<String, BibleBookData>? = null

    // Load Bible book data from assets
    suspend fun loadBookFromAssets(context: Context, bookName: String, language: BibleLanguage = BibleLanguage.ENGLISH): BibleBookData? {
        return withContext(Dispatchers.IO) {
            try {
                val fileName = getBookFileName(bookName)
                val folder = if (language == BibleLanguage.URDU) "bible/urdu" else "bible"
                val json = context.assets.open("$folder/$fileName").bufferedReader().use { it.readText() }
                parseBibleBookData(json)
            } catch (e: Exception) {
                android.util.Log.e("BIBLE", "Error loading book $bookName (${language.code}): ${e.message}")
                null
            }
        }
    }

    // Get chapter verses from offline storage
    suspend fun getChapter(context: Context, bookName: String, chapter: Int, language: BibleLanguage = BibleLanguage.ENGLISH): List<BibleVerse> {
        val bookData = loadBookFromAssets(context, bookName, language)
        return bookData?.chapters?.find { it.chapter == chapter }?.verses ?: emptyList()
    }

    private fun getBookFileName(bookName: String): String {
        return when (bookName.lowercase().replace(" ", "")) {
            "genesis" -> "genesis.json"
            "exodus" -> "exodus.json"
            "leviticus" -> "leviticus.json"
            "numbers" -> "numbers.json"
            "deuteronomy" -> "deuteronomy.json"
            "joshua" -> "joshua.json"
            "judges" -> "judges.json"
            "ruth" -> "ruth.json"
            "1samuel" -> "1samuel.json"
            "2samuel" -> "2samuel.json"
            "1kings" -> "1kings.json"
            "2kings" -> "2kings.json"
            "1chronicles" -> "1chronicles.json"
            "2chronicles" -> "2chronicles.json"
            "ezra" -> "ezra.json"
            "nehemiah" -> "nehemiah.json"
            "esther" -> "esther.json"
            "job" -> "job.json"
            "psalms" -> "psalms.json"
            "proverbs" -> "proverbs.json"
            "ecclesiastes" -> "ecclesiastes.json"
            "songofsolomon" -> "songofsolomon.json"
            "isaiah" -> "isaiah.json"
            "jeremiah" -> "jeremiah.json"
            "lamentations" -> "lamentations.json"
            "ezekiel" -> "ezekiel.json"
            "daniel" -> "daniel.json"
            "hosea" -> "hosea.json"
            "joel" -> "joel.json"
            "amos" -> "amos.json"
            "obadiah" -> "obadiah.json"
            "jonah" -> "jonah.json"
            "micah" -> "micah.json"
            "nahum" -> "nahum.json"
            "habakkuk" -> "habakkuk.json"
            "zephaniah" -> "zephaniah.json"
            "haggai" -> "haggai.json"
            "zechariah" -> "zechariah.json"
            "malachi" -> "malachi.json"
            "matthew" -> "matthew.json"
            "mark" -> "mark.json"
            "luke" -> "luke.json"
            "john" -> "john.json"
            "acts" -> "acts.json"
            "romans" -> "romans.json"
            "1corinthians" -> "1corinthians.json"
            "2corinthians" -> "2corinthians.json"
            "galatians" -> "galatians.json"
            "ephesians" -> "ephesians.json"
            "philippians" -> "philippians.json"
            "colossians" -> "colossians.json"
            "1thessalonians" -> "1thessalonians.json"
            "2thessalonians" -> "2thessalonians.json"
            "1timothy" -> "1timothy.json"
            "2timothy" -> "2timothy.json"
            "titus" -> "titus.json"
            "philemon" -> "philemon.json"
            "hebrews" -> "hebrews.json"
            "james" -> "james.json"
            "1peter" -> "1peter.json"
            "2peter" -> "2peter.json"
            "1john" -> "1john.json"
            "2john" -> "2john.json"
            "3john" -> "3john.json"
            "jude" -> "jude.json"
            "revelation" -> "revelation.json"
            else -> "${bookName.lowercase().replace(" ", "")}.json"
        }
    }

    private fun parseBibleBookData(json: String): BibleBookData? {
        return try {
            Gson().fromJson(json, BibleBookData::class.java)
        } catch (e: Exception) {
            android.util.Log.e("BIBLE", "Parse error: ${e.message}")
            null
        }
    }
}

