// Fetch Bible Chapter from Offline Storage
suspend fun fetchBibleChapter(context: Context, book: String, chapter: Int, language: BibleLanguage = BibleLanguage.ENGLISH): List<BibleVerse> {
    return BibleStorage.getChapter(context, book, chapter, language)
}

// Bible Screen
@OptIn(ExperimentalMaterial3Api::class)
// Bible Search Result Data Class
data class BibleSearchResult(
    val book: BibleBook,
    val chapter: Int,
    val verse: BibleVerse,
    val language: BibleLanguage
)

// Search function for Bible verses
suspend fun searchBibleVerses(
    context: Context,
    query: String,
    language: BibleLanguage
): List<BibleSearchResult> {
    if (query.length < 2) return emptyList()

    return withContext(Dispatchers.IO) {
        val results = mutableListOf<BibleSearchResult>()
        val searchQuery = query.lowercase()

        for (book in allBibleBooks) {
            try {
                val bookData = BibleStorage.loadBookFromAssets(context, book.name, language)
                bookData?.chapters?.forEach { chapter ->
                    chapter.verses.forEach { verse ->
                        if (verse.text.lowercase().contains(searchQuery)) {
                            results.add(BibleSearchResult(book, chapter.chapter, verse, language))
                        }
                    }
                }
            } catch (e: Exception) {
                // Skip books that fail to load
            }

            // Limit results for performance
            if (results.size >= 50) return@withContext results.take(50)
        }
        results
    }
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun BibleScreen(onBack: () -> Unit) {
    val context = LocalContext.current
    var selectedBook by remember { mutableStateOf<BibleBook?>(null) }
    var selectedChapter by remember { mutableStateOf<Int?>(null) }
    var verses by remember { mutableStateOf<List<BibleVerse>>(emptyList()) }
    var isLoading by remember { mutableStateOf(false) }
    var showBookSelector by remember { mutableStateOf(true) }
    var selectedTestament by remember { mutableStateOf("OT") }
    var fontSize by remember { mutableStateOf(16f) }
    var selectedLanguage by remember { mutableStateOf(BibleLanguage.ENGLISH) }

    // Search states
    var isSearching by remember { mutableStateOf(false) }
    var searchQuery by remember { mutableStateOf("") }
    var searchResults by remember { mutableStateOf<List<BibleSearchResult>>(emptyList()) }
    var isSearchLoading by remember { mutableStateOf(false) }
    val coroutineScope = rememberCoroutineScope()

    // Load chapter when selected (offline)
    LaunchedEffect(selectedBook, selectedChapter, selectedLanguage) {
        if (selectedBook != null && selectedChapter != null) {
            isLoading = true
            verses = fetchBibleChapter(context, selectedBook!!.name, selectedChapter!!, selectedLanguage)
            isLoading = false
            showBookSelector = false
        }
    }

    // Search when query changes
    LaunchedEffect(searchQuery, selectedLanguage) {
        if (searchQuery.length >= 2) {
            isSearchLoading = true
            delay(300) // Debounce
            searchResults = searchBibleVerses(context, searchQuery, selectedLanguage)
            isSearchLoading = false
        } else {
            searchResults = emptyList()
        }
    }

    BackHandler(enabled = isSearching || !showBookSelector || selectedBook != null) {
        when {
            isSearching -> {
                isSearching = false
                searchQuery = ""
                searchResults = emptyList()
            }
            !showBookSelector && selectedChapter != null -> {
                selectedChapter = null
                showBookSelector = true
            }
            selectedBook != null && selectedChapter == null -> {
                selectedBook = null
            }
            else -> onBack()
        }
    }

    Scaffold(
        containerColor = MaterialTheme.colorScheme.background,
        topBar = {
            if (isSearching) {
                // Search TopAppBar
                TopAppBar(
                    title = {
                        OutlinedTextField(
                            value = searchQuery,
                            onValueChange = { searchQuery = it },
                            placeholder = { 
                                Text(
                                    if (selectedLanguage == BibleLanguage.URDU) "آیات تلاش کریں..." else "Search verses...",
                                    color = MaterialTheme.colorScheme.onSurfaceVariant
                                )
                            },
                            singleLine = true,
                            modifier = Modifier.fillMaxWidth(),
                            colors = OutlinedTextFieldDefaults.colors(
                                focusedBorderColor = MaterialTheme.colorScheme.primary,
                                unfocusedBorderColor = Color.Transparent,
                                focusedContainerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f),
                                unfocusedContainerColor = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f)
                            ),
                            shape = RoundedCornerShape(12.dp),
                            textStyle = MaterialTheme.typography.bodyLarge
                        )
                    },
                    navigationIcon = {
                        IconButton(onClick = {
                            isSearching = false
                            searchQuery = ""
                            searchResults = emptyList()
                        }) {
                            Icon(
                                Icons.AutoMirrored.Rounded.ArrowBack,
                                contentDescription = "Close Search"
                            )
                        }
                    },
                    actions = {
                        // Language toggle in search mode
                        Surface(
                            onClick = {
                                selectedLanguage = if (selectedLanguage == BibleLanguage.ENGLISH) 
                                    BibleLanguage.URDU else BibleLanguage.ENGLISH
                            },
                            shape = RoundedCornerShape(8.dp),
                            color = MaterialTheme.colorScheme.primaryContainer
                        ) {
                            Text(
                                text = if (selectedLanguage == BibleLanguage.ENGLISH) "اُردُو" else "ENG",
                                modifier = Modifier.padding(horizontal = 8.dp, vertical = 4.dp),
                                style = MaterialTheme.typography.labelSmall,
                                fontWeight = FontWeight.Bold,
                                color = MaterialTheme.colorScheme.onPrimaryContainer
                            )
                        }
                        Spacer(modifier = Modifier.width(8.dp))
                    },
                    colors = TopAppBarDefaults.topAppBarColors(
                        containerColor = Color.Transparent
                    )
                )
            } else {
                // Normal TopAppBar
                TopAppBar(
                    title = {
                        Column {
                            Text(
                                if (selectedBook != null && selectedChapter != null) 
                                    "${selectedBook!!.getDisplayName(selectedLanguage)} $selectedChapter"
                                else if (selectedBook != null)
                                    if (selectedLanguage == BibleLanguage.URDU) "باب منتخب کریں" else "Select Chapter"
                                else 
                                    if (selectedLanguage == BibleLanguage.URDU) "بائبل" else "Bible",
                                style = MaterialTheme.typography.titleLarge
                            )
                            if (selectedBook != null && selectedChapter != null) {
                                Text(
                                    if (selectedLanguage == BibleLanguage.URDU) "${verses.size} آیات" else "${verses.size} verses",
                                    style = MaterialTheme.typography.bodySmall,
                                    color = MaterialTheme.colorScheme.onSurfaceVariant
                                )
                            }
                        }
                    },
                    navigationIcon = {
                        IconButton(onClick = {
                            when {
                                !showBookSelector && selectedChapter != null -> {
                                    selectedChapter = null
                                    showBookSelector = true
                                }
                                selectedBook != null && selectedChapter == null -> {
                                    selectedBook = null
                                }
                                else -> onBack()
                            }
                        }) {
                            Icon(
                                Icons.AutoMirrored.Rounded.ArrowBack,
                                contentDescription = "Back"
                            )
                        }
                    },
                    actions = {
                        // Search icon
                        IconButton(onClick = { isSearching = true }) {
                            Icon(
                                Icons.Rounded.Search,
                                contentDescription = if (selectedLanguage == BibleLanguage.URDU) "تلاش" else "Search"
                            )
                        }
                        // Language toggle
                        Surface(
                            onClick = {
                                selectedLanguage = if (selectedLanguage == BibleLanguage.ENGLISH) 
                                    BibleLanguage.URDU else BibleLanguage.ENGLISH
                            },
                            shape = RoundedCornerShape(8.dp),
                            color = MaterialTheme.colorScheme.primaryContainer
                        ) {
                            Text(
                                text = if (selectedLanguage == BibleLanguage.ENGLISH) "اُردُو" else "ENG",
                                modifier = Modifier.padding(horizontal = 12.dp, vertical = 6.dp),
                                style = MaterialTheme.typography.labelMedium,
                                fontWeight = FontWeight.Bold,
                                color = MaterialTheme.colorScheme.onPrimaryContainer
                            )
                        }
                        Spacer(modifier = Modifier.width(8.dp))
                        // Font size controls when reading
                        if (!showBookSelector && verses.isNotEmpty()) {
                            IconButton(onClick = { if (fontSize > 12f) fontSize -= 2f }) {
                                Text("A-", fontWeight = FontWeight.Bold)
                            }
                            IconButton(onClick = { if (fontSize < 32f) fontSize += 2f }) {
                                Text("A+", fontWeight = FontWeight.Bold)
                            }
                        }
                    },
                    colors = TopAppBarDefaults.topAppBarColors(
                        containerColor = Color.Transparent
                    )
                )
            }
        }
    ) { padding ->
        Box(
            modifier = Modifier
                .fillMaxSize()
                .padding(padding)
        ) {
            val biblePageKey = when {
                isSearching -> 0
                showBookSelector && selectedBook == null -> 1
                showBookSelector && selectedBook != null && selectedChapter == null -> 2
                isLoading -> 3
                verses.isNotEmpty() -> 4
                else -> 5
            }

            AnimatedContent(
                targetState = biblePageKey,
                transitionSpec = {
                    if (targetState > initialState) {
                        slideInHorizontally { it } togetherWith slideOutHorizontally { -it }
                    } else {
                        slideInHorizontally { -it } togetherWith slideOutHorizontally { it }
                    }
                },
                label = "bibleTransition"
            ) { page ->
                when (page) {
                // Search Results View
                0 -> {
                    BibleSearchResultsView(
                        query = searchQuery,
                        results = searchResults,
                        isLoading = isSearchLoading,
                        language = selectedLanguage,
                        onResultClick = { result ->
                            selectedBook = result.book
                            selectedChapter = result.chapter
                            isSearching = false
                            searchQuery = ""
                            searchResults = emptyList()
                        }
                    )
                }
                1 -> {
                    // Book Selection
                    BibleBookSelector(
                        selectedTestament = selectedTestament,
                        onTestamentChange = { selectedTestament = it },
                        onBookSelect = { selectedBook = it },
                        language = selectedLanguage
                    )
                }
                2 -> {
                    // Chapter Selection
                    val book = selectedBook ?: return@AnimatedContent
                    BibleChapterSelector(
                        book = book,
                        onChapterSelect = { selectedChapter = it },
                        language = selectedLanguage
                    )
                }
                3 -> {
                    // Loading
                    Box(
                        modifier = Modifier.fillMaxSize(),
                        contentAlignment = Alignment.Center
                    ) {
                        Column(horizontalAlignment = Alignment.CenterHorizontally) {
                            CircularProgressIndicator(
                                color = MaterialTheme.colorScheme.primary
                            )
                            Spacer(modifier = Modifier.height(16.dp))
                            Text("Loading chapter...")
                        }
                    }
                }
                4 -> {
                    // Bible Content
                    val book = selectedBook ?: return@AnimatedContent
                    val chapter = selectedChapter ?: return@AnimatedContent
                    BibleContentView(
                        book = book,
                        chapter = chapter,
                        verses = verses,
                        fontSize = fontSize,
                        language = selectedLanguage,
                        onPreviousChapter = {
                            if (chapter > 1) {
                                selectedChapter = chapter - 1
                            }
                        },
                        onNextChapter = {
                            if (chapter < book.chapters) {
                                selectedChapter = chapter + 1
                            }
                        }
                    )
                }
                else -> {
                    // Error or No Content
                    Box(
                        modifier = Modifier.fillMaxSize(),
                        contentAlignment = Alignment.Center
                    ) {
                        Column(
                            horizontalAlignment = Alignment.CenterHorizontally,
                            modifier = Modifier.padding(24.dp)
                        ) {
                            Text("", fontSize = 64.sp)
                            Spacer(modifier = Modifier.height(16.dp))
                            Text(
                                "Chapter Not Available",
                                style = MaterialTheme.typography.titleMedium,
                                color = MaterialTheme.colorScheme.onBackground
                            )
                            Spacer(modifier = Modifier.height(8.dp))
                            Text(
                                "This chapter is not yet available offline.\nMore content will be added in future updates.",
                                style = MaterialTheme.typography.bodyMedium,
                                color = MaterialTheme.colorScheme.onSurfaceVariant,
                                textAlign = TextAlign.Center
                            )
                            Spacer(modifier = Modifier.height(16.dp))
                            Button(onClick = {
                                selectedChapter = null
                                showBookSelector = true
                            }) {
                                Text("Select Another Chapter")
                            }
                        }
                    }
                }
                }
            }
        }
    }
}

@Composable
fun BibleBookSelector(
    selectedTestament: String,
    onTestamentChange: (String) -> Unit,
    onBookSelect: (BibleBook) -> Unit,
    language: BibleLanguage = BibleLanguage.ENGLISH
) {
    val books = if (selectedTestament == "OT") oldTestamentBooks else newTestamentBooks
    val isUrdu = language == BibleLanguage.URDU

    Column(modifier = Modifier.fillMaxSize()) {
        // Testament Tabs
        Row(
            modifier = Modifier
                .fillMaxWidth()
                .padding(horizontal = 16.dp, vertical = 8.dp),
            horizontalArrangement = Arrangement.spacedBy(12.dp)
        ) {
            TestamentTab(
                title = if (isUrdu) "پُرانا عہد نامہ" else "Old Testament",
                selected = selectedTestament == "OT",
                onClick = { onTestamentChange("OT") },
                modifier = Modifier.weight(1f)
            )
            TestamentTab(
                title = if (isUrdu) "نیا عہد نامہ" else "New Testament",
                selected = selectedTestament == "NT",
                onClick = { onTestamentChange("NT") },
                modifier = Modifier.weight(1f)
            )
        }

        // Books Grid
        val configuration = LocalConfiguration.current
        val columns = when {
            configuration.screenWidthDp >= 840 -> 4
            configuration.screenWidthDp >= 600 -> 3
            else -> 2
        }

        LazyVerticalGrid(
            columns = GridCells.Fixed(columns),
            modifier = Modifier.fillMaxSize(),
            contentPadding = PaddingValues(16.dp),
            horizontalArrangement = Arrangement.spacedBy(12.dp),
            verticalArrangement = Arrangement.spacedBy(12.dp)
        ) {
            items(books.size, key = { index -> books[index].name }) { index ->
                AnimatedBibleBookCard(
                    book = books[index],
                    index = index,
                    onClick = { onBookSelect(books[index]) },
                    language = language
                )
            }
        }
    }
}

@Composable
fun TestamentTab(
    title: String,
    selected: Boolean,
    onClick: () -> Unit,
    modifier: Modifier = Modifier
) {
    val backgroundColor = if (selected) MaterialTheme.colorScheme.primary
                     else MaterialTheme.colorScheme.surfaceVariant

    val textColor = if (selected) Color.White
                     else MaterialTheme.colorScheme.onSurfaceVariant

    Surface(
        onClick = onClick,
        modifier = modifier
            .height(48.dp),
        shape = RoundedCornerShape(12.dp),
        color = backgroundColor
    ) {
        Box(contentAlignment = Alignment.Center) {
            Text(
                text = title,
                style = MaterialTheme.typography.labelLarge,
                color = textColor,
                fontWeight = if (selected) FontWeight.Bold else FontWeight.Medium
            )
        }
    }
}

// Bible Book Card
