fun AnimatedBibleBookCard(
    book: BibleBook,
    index: Int,
    onClick: () -> Unit,
    language: BibleLanguage = BibleLanguage.ENGLISH
) {
    BibleBookCard(
        book = book,
        onClick = onClick,
        language = language
    )
