@Composable
fun SongDetailScreen(song: SongItem) {
    val isUrduTitle = isUrduText(song.title)
    val isUrduLyrics = isUrduText(song.lyrics)

    // Responsive padding for larger screens
    val configuration = LocalConfiguration.current
    val horizontalPadding = when {
        configuration.screenWidthDp >= 840 -> 120.dp  // Large tablets
        configuration.screenWidthDp >= 600 -> 60.dp   // Small tablets
        else -> 24.dp                                  // Phones
    }

    LazyColumn(
        modifier = Modifier.fillMaxSize(),
        contentPadding = PaddingValues(horizontal = horizontalPadding, vertical = 24.dp),
        horizontalAlignment = Alignment.CenterHorizontally
    ) {
        item {
            Column(horizontalAlignment = Alignment.CenterHorizontally) {
                // Category Badge
                Surface(
                    shape = RoundedCornerShape(20.dp),
                    color = MaterialTheme.colorScheme.primaryContainer
                ) {
                        Text(
                            text = song.category.uppercase(),
                            modifier = Modifier.padding(horizontal = 16.dp, vertical = 6.dp),
                            style = MaterialTheme.typography.labelMedium,
                            color = MaterialTheme.colorScheme.onPrimaryContainer,
                            letterSpacing = 2.sp
                        )
                    }

                    Spacer(modifier = Modifier.height(16.dp))

                    // Heading (for Psalms)
                    if (song.heading != null) {
                        val isUrduHeading = isUrduText(song.heading)
                        Text(
                            text = song.heading,
                            style = if (isUrduHeading) {
                                MaterialTheme.typography.titleMedium.copy(
                                    fontFamily = NotoNastaliqUrdu,
                                    fontSize = 16.sp
                                )
                            } else {
                                MaterialTheme.typography.titleMedium
                            },
                            color = MaterialTheme.colorScheme.primary,
                            textAlign = TextAlign.Center
                        )
                        Spacer(modifier = Modifier.height(8.dp))
                    }

                    // Title
                    Text(
                        text = song.title,
                        style = if (isUrduTitle) {
                            MaterialTheme.typography.headlineMedium.copy(
                                fontFamily = NotoNastaliqUrdu,
                                fontSize = 28.sp,
                                lineHeight = 44.sp,
                                fontWeight = FontWeight.Bold
                            )
                        } else {
                            MaterialTheme.typography.headlineMedium.copy(
                                fontWeight = FontWeight.Bold
                            )
                        },
                        textAlign = TextAlign.Center,
                        color = MaterialTheme.colorScheme.onBackground
                    )

                    Spacer(modifier = Modifier.height(24.dp))

                    // Decorative Divider
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.Center,
                        modifier = Modifier.fillMaxWidth()
                    ) {
                        Box(
                            modifier = Modifier
                                .width(40.dp)
                                .height(1.dp)
                                .background(
                                    brush = Brush.horizontalGradient(
                                        colors = listOf(
                                            Color.Transparent,
                                            MaterialTheme.colorScheme.primary.copy(alpha = 0.5f)
                                        )
                                    )
                                )
                        )
                        Spacer(modifier = Modifier.width(8.dp))
                        Box(
                            modifier = Modifier
                                .size(8.dp)
                                .clip(CircleShape)
                                .background(MaterialTheme.colorScheme.primary)
                        )
                        Spacer(modifier = Modifier.width(8.dp))
                        Box(
                            modifier = Modifier
                                .width(40.dp)
                                .height(1.dp)
                                .background(
                                    brush = Brush.horizontalGradient(
                                        colors = listOf(
                                            MaterialTheme.colorScheme.primary.copy(alpha = 0.5f),
                                            Color.Transparent
                                        )
                                    )
                                )
                        )
                    }

                    Spacer(modifier = Modifier.height(32.dp))

                    // Lyrics
                    Text(
                        text = song.lyrics,
                        style = if (isUrduLyrics) {
                            MaterialTheme.typography.bodyLarge.copy(
                                fontFamily = NotoNastaliqUrdu,
                                fontSize = 22.sp,
                                lineHeight = 52.sp
                            )
                        } else {
                            MaterialTheme.typography.bodyLarge.copy(
                                lineHeight = 32.sp
                            )
                        },
                        textAlign = TextAlign.Center,
                        color = MaterialTheme.colorScheme.onBackground
                    )

                    Spacer(modifier = Modifier.height(80.dp))
                }
            }
        }
    }

