// Bible Search Results View
@Composable
fun BibleSearchResultsView(
    query: String,
    results: List<BibleSearchResult>,
    isLoading: Boolean,
    language: BibleLanguage,
    onResultClick: (BibleSearchResult) -> Unit
) {
    val isUrdu = language == BibleLanguage.URDU

    // Urdu font provider
    val provider = GoogleFont.Provider(
        providerAuthority = "com.google.android.gms.fonts",
        providerPackage = "com.google.android.gms",
        certificates = R.array.com_google_android_gms_fonts_certs
    )
    val urduFontFamily = FontFamily(
        Font(GoogleFont("Noto Nastaliq Urdu"), provider)
    )

    Column(modifier = Modifier.fillMaxSize()) {
        // Search info header with modern design
        if (query.isNotEmpty()) {
            Surface(
                modifier = Modifier.fillMaxWidth(),
                color = MaterialTheme.colorScheme.surfaceVariant.copy(alpha = 0.5f)
            ) {
                CompositionLocalProvider(
                    LocalLayoutDirection provides if (isUrdu) LayoutDirection.Rtl else LayoutDirection.Ltr
                ) {
                    Row(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(horizontal = 20.dp, vertical = 16.dp),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Column {
                            Text(
                                text = if (isUrdu) "نتائج تلاش" else "Search Results",
                                style = MaterialTheme.typography.labelLarge,
                                color = MaterialTheme.colorScheme.onSurfaceVariant,
                                fontWeight = FontWeight.Bold
                            )
                            Spacer(modifier = Modifier.height(4.dp))
                            if (results.isNotEmpty()) {
                                Text(
                                    text = if (isUrdu) "${results.size} نتائج ملے" else "${results.size} results found",
                                    style = MaterialTheme.typography.bodyMedium,
                                    color = MaterialTheme.colorScheme.onSurfaceVariant
                                )
                            } else if (!isLoading) {
                                Text(
                                    text = if (isUrdu) "کوئی نتیجہ نہیں ملا" else "No results found",
                                    style = MaterialTheme.typography.bodyMedium,
                                    color = MaterialTheme.colorScheme.error
                                )
                            }
                        }

                        if (results.isNotEmpty()) {
                            Surface(
                                shape = RoundedCornerShape(20.dp),
                                color = MaterialTheme.colorScheme.primaryContainer
                            ) {
                                Text(
                                    text = "${results.size}",
                                    style = MaterialTheme.typography.labelLarge,
                                    fontWeight = FontWeight.Bold,
                                    color = MaterialTheme.colorScheme.onPrimaryContainer,
                                    modifier = Modifier.padding(horizontal = 12.dp, vertical = 6.dp)
                                )
                            }
                        }
                    }
                }
            }
        }

        when {
            isLoading -> {
                Box(
                    modifier = Modifier.fillMaxSize(),
                    contentAlignment = Alignment.Center
                ) {
                    Column(horizontalAlignment = Alignment.CenterHorizontally) {
                        CircularProgressIndicator(
                            color = MaterialTheme.colorScheme.primary
                        )
                        Spacer(modifier = Modifier.height(16.dp))
                        Text(
                            text = if (isUrdu) "تلاش جاری ہے..." else "Searching...",
                            style = MaterialTheme.typography.bodyMedium,
                            color = MaterialTheme.colorScheme.onSurfaceVariant
                        )
                    }
                }
            }
            results.isEmpty() && query.length >= 2 -> {
                Box(
                    modifier = Modifier.fillMaxSize(),
                    contentAlignment = Alignment.Center
                ) {
                    Column(
                        horizontalAlignment = Alignment.CenterHorizontally,
                        modifier = Modifier.padding(32.dp)
                    ) {
                        Text(
                            text = if (isUrdu) "کوئی آیت نہیں ملی" else "No verses found",
                            style = MaterialTheme.typography.titleMedium,
                            fontWeight = FontWeight.Bold,
                            color = MaterialTheme.colorScheme.onSurface
                        )
                        Spacer(modifier = Modifier.height(8.dp))
                        Text(
                            text = if (isUrdu) "کوئی اور لفظ استعمال کریں" else "Try different search terms",
                            style = MaterialTheme.typography.bodyMedium,
                            color = MaterialTheme.colorScheme.onSurfaceVariant,
                            textAlign = TextAlign.Center
                        )
                    }
                }
            }
            query.length < 2 -> {
                Box(
                    modifier = Modifier.fillMaxSize(),
                    contentAlignment = Alignment.Center
                ) {
                    Column(
                        horizontalAlignment = Alignment.CenterHorizontally,
                        modifier = Modifier.padding(32.dp)
                    ) {
                        Text(
                            text = if (isUrdu) "تلاش شروع کریں" else "Start typing to search",
                            style = MaterialTheme.typography.titleMedium,
                            fontWeight = FontWeight.Bold,
                            color = MaterialTheme.colorScheme.onSurface
                        )
                        Spacer(modifier = Modifier.height(8.dp))
                        Text(
                            text = if (isUrdu) "کم از کم 2 حروف درج کریں" else "Enter at least 2 characters",
                            style = MaterialTheme.typography.bodyMedium,
                            color = MaterialTheme.colorScheme.onSurfaceVariant,
                            textAlign = TextAlign.Center
                        )
                    }
                }
            }
            else -> {
                LazyColumn(
                    modifier = Modifier.fillMaxSize(),
                    contentPadding = PaddingValues(16.dp),
                    verticalArrangement = Arrangement.spacedBy(12.dp)
                ) {
                    items(results.size) { index ->
                        ModernSearchResultCard(
                            result = results[index],
                            query = query,
                            onClick = { onResultClick(results[index]) },
                            isUrdu = isUrdu,
                            urduFontFamily = urduFontFamily
                        )
                    }
                }
            }
        }
    }
}

@Composable
fun ModernSearchResultCard(
    result: BibleSearchResult,
    query: String,
    onClick: () -> Unit,
    isUrdu: Boolean,
    urduFontFamily: FontFamily
) {
    Card(
        onClick = onClick,
        shape = RoundedCornerShape(16.dp),
        colors = CardDefaults.cardColors(
            containerColor = MaterialTheme.colorScheme.surface
        ),
        elevation = CardDefaults.cardElevation(
            defaultElevation = 1.dp,
            pressedElevation = 4.dp
        )
    ) {
        CompositionLocalProvider(
            LocalLayoutDirection provides if (isUrdu) LayoutDirection.Rtl else LayoutDirection.Ltr
        ) {
            Column(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(16.dp)
            ) {
                // Book, Chapter, Verse reference
                Row(
                    modifier = Modifier.fillMaxWidth(),
                    horizontalArrangement = Arrangement.SpaceBetween,
                    verticalAlignment = Alignment.CenterVertically
                ) {
                    Row(
                        horizontalArrangement = Arrangement.spacedBy(8.dp),
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Surface(
                            shape = RoundedCornerShape(8.dp),
                            color = MaterialTheme.colorScheme.primaryContainer
                        ) {
                            Text(
                                text = result.book.getDisplayName(if (isUrdu) BibleLanguage.URDU else BibleLanguage.ENGLISH),
                                style = MaterialTheme.typography.labelMedium,
                                fontWeight = FontWeight.Bold,
                                color = MaterialTheme.colorScheme.onPrimaryContainer,
                                modifier = Modifier.padding(horizontal = 10.dp, vertical = 4.dp)
                            )
                        }
                        Text(
                            text = "${result.chapter}:${result.verse}",
                            style = MaterialTheme.typography.labelLarge,
                            fontWeight = FontWeight.SemiBold,
                            color = MaterialTheme.colorScheme.primary
                        )
                    }

                    Icon(
                        Icons.AutoMirrored.Rounded.ArrowForward,
                        contentDescription = null,
                        modifier = Modifier.size(18.dp),
                        tint = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }

                Spacer(modifier = Modifier.height(12.dp))

                // Verse text with highlighted search term
                val highlightedText = buildAnnotatedString {
                    val text = result.verse.text
                    var lastIndex = 0

                    // Find and highlight all occurrences of query (case insensitive)
                    val lowerText = text.lowercase()
                    val lowerQuery = query.lowercase()
                    var index = lowerText.indexOf(lowerQuery)

                    while (index >= 0) {
                        // Add normal text before match
                        append(text.substring(lastIndex, index))

                        // Add highlighted match
                        withStyle(
                            style = SpanStyle(
                                background = MaterialTheme.colorScheme.primaryContainer,
                                color = MaterialTheme.colorScheme.onPrimaryContainer,
                                fontWeight = FontWeight.Bold
                            )
                        ) {
                            append(text.substring(index, index + query.length))
                        }

                        lastIndex = index + query.length
                        index = lowerText.indexOf(lowerQuery, lastIndex)
                    }

                    // Add remaining text
                    if (lastIndex < text.length) {
                        append(text.substring(lastIndex))
                    }
                }

                Text(
                    text = highlightedText,
                    style = MaterialTheme.typography.bodyMedium.copy(
                        fontFamily = if (isUrdu) urduFontFamily else FontFamily.Default,
                        lineHeight = if (isUrdu) 28.sp else 22.sp
                    ),
                    color = MaterialTheme.colorScheme.onSurface,
                    maxLines = 4,
                    overflow = TextOverflow.Ellipsis
                )
            }
        }
    }
}

@Composable
fun BibleContentView(
    book: BibleBook,
    chapter: Int,
    verses: List<BibleVerse>,
    fontSize: Float,
    language: BibleLanguage = BibleLanguage.ENGLISH,
    onPreviousChapter: () -> Unit,
    onNextChapter: () -> Unit
) {
    val configuration = LocalConfiguration.current
    val horizontalPadding = when {
        configuration.screenWidthDp >= 840 -> 120.dp
        configuration.screenWidthDp >= 600 -> 60.dp
        else -> 20.dp
    }
    val isUrdu = language == BibleLanguage.URDU
    val adjustedFontSize = if (isUrdu) fontSize + 2 else fontSize
    val lineHeightMultiplier = if (isUrdu) 2.0f else 1.7f

    // Urdu font provider
    val provider = GoogleFont.Provider(
        providerAuthority = "com.google.android.gms.fonts",
        providerPackage = "com.google.android.gms",
        certificates = R.array.com_google_android_gms_fonts_certs
    )
    val urduFontFamily = FontFamily(
        Font(GoogleFont("Noto Nastaliq Urdu"), provider)
    )

    // Track scroll state for reading progress
    val listState = rememberLazyListState()
    val coroutineScope = rememberCoroutineScope()
    val showScrollToTop = remember {
        derivedStateOf { listState.firstVisibleItemIndex > 5 }
    }

    Box(modifier = Modifier.fillMaxSize()) {
        Column(modifier = Modifier.fillMaxSize()) {
            // Reading Progress Bar with smooth animation
            val progress = remember {
                derivedStateOf {
                    if (verses.isEmpty()) 0f
                    else (listState.firstVisibleItemIndex.toFloat() / verses.size.toFloat()).coerceIn(0f, 1f)
                }
            }

            LinearProgressIndicator(
                progress = { progress.value },
                modifier = Modifier.fillMaxWidth(),
                color = MaterialTheme.colorScheme.primary,
                trackColor = MaterialTheme.colorScheme.surfaceVariant
            )

            // Chapter Header Card
            Surface(
                modifier = Modifier.fillMaxWidth(),
                color = MaterialTheme.colorScheme.primaryContainer.copy(alpha = 0.3f),
                tonalElevation = 1.dp
            ) {
                CompositionLocalProvider(
                    LocalLayoutDirection provides if (isUrdu) LayoutDirection.Rtl else LayoutDirection.Ltr
                ) {
                    Column(
                        modifier = Modifier
                            .fillMaxWidth()
                            .padding(horizontal = horizontalPadding, vertical = 16.dp)
                    ) {
                        Text(
                            text = book.getDisplayName(language),
                            style = MaterialTheme.typography.titleLarge,
                            fontWeight = FontWeight.Bold,
                            color = MaterialTheme.colorScheme.onSurface
                        )
                        Spacer(modifier = Modifier.height(4.dp))
                        Row(
                            verticalAlignment = Alignment.CenterVertically,
                            horizontalArrangement = Arrangement.spacedBy(12.dp)
                        ) {
                            Text(
                                text = if (isUrdu) "باب $chapter" else "Chapter $chapter",
                                style = MaterialTheme.typography.bodyLarge,
                                color = MaterialTheme.colorScheme.primary,
                                fontWeight = FontWeight.SemiBold
                            )
                            Text(
                                text = "-",
                                style = MaterialTheme.typography.bodyLarge,
                                color = MaterialTheme.colorScheme.onSurfaceVariant
                            )
                            Text(
                                text = if (isUrdu) "${verses.size} آیات" else "${verses.size} verses",
                                style = MaterialTheme.typography.bodyMedium,
                                color = MaterialTheme.colorScheme.onSurfaceVariant
                            )
                        }
                    }
                }
            }

            // Verses with enhanced design
            LazyColumn(
                state = listState,
                modifier = Modifier
                    .weight(1f)
                    .fillMaxWidth(),
                contentPadding = PaddingValues(
                    start = horizontalPadding,
                    end = horizontalPadding,
                    top = 20.dp,
                    bottom = 100.dp
                )
            ) {
                items(verses.size) { index ->
                    val verse = verses[index]
                    val isFirstVerse = index == 0

                    CompositionLocalProvider(
                        LocalLayoutDirection provides if (isUrdu) LayoutDirection.Rtl else LayoutDirection.Ltr
                    ) {
                        Column(
                            modifier = Modifier
                                .fillMaxWidth()
                                .padding(
                                    top = if (isFirstVerse) 0.dp else if (isUrdu) 12.dp else 8.dp
                                )
                        ) {
                            Row(
                                modifier = Modifier.fillMaxWidth(),
                                horizontalArrangement = Arrangement.spacedBy(8.dp)
                            ) {
                                // Verse Number (plain text)
                                Text(
                                    text = "${verse.verse}",
                                    style = MaterialTheme.typography.labelSmall.copy(
                                        fontSize = (adjustedFontSize - 6).sp
                                    ),
                                    color = MaterialTheme.colorScheme.primary,
                                    fontWeight = FontWeight.Bold,
                                    modifier = Modifier.padding(top = 4.dp)
                                )

                                // Verse Text
                                Text(
                                    text = verse.text,
                                    style = MaterialTheme.typography.bodyLarge.copy(
                                        fontSize = adjustedFontSize.sp,
                                        lineHeight = (adjustedFontSize * lineHeightMultiplier).sp,
                                        fontFamily = if (isUrdu) urduFontFamily else FontFamily.Default
                                    ),
                                    color = MaterialTheme.colorScheme.onBackground,
                                    modifier = Modifier.weight(1f)
                                )
                            }

                            // Divider between verses (subtle)
                            if (index < verses.size - 1) {
                                Spacer(modifier = Modifier.height(if (isUrdu) 12.dp else 8.dp))
                            }
                        }
                    }
                }

                // End of chapter spacer
                item {
                    Spacer(modifier = Modifier.height(20.dp))
                }
            }
        }

        // Floating Navigation Bar at bottom
        Surface(
            modifier = Modifier
                .align(Alignment.BottomCenter)
                .fillMaxWidth()
                .padding(horizontal = 16.dp, vertical = 16.dp),
            shape = RoundedCornerShape(16.dp),
            color = MaterialTheme.colorScheme.surface,
            shadowElevation = 8.dp,
            tonalElevation = 3.dp
        ) {
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(12.dp),
                horizontalArrangement = Arrangement.SpaceBetween,
                verticalAlignment = Alignment.CenterVertically
            ) {
                // Previous Chapter Button
                FilledTonalButton(
                    onClick = onPreviousChapter,
                    enabled = chapter > 1,
                    shape = RoundedCornerShape(12.dp),
                    modifier = Modifier.weight(1f)
                ) {
                    Icon(
                        Icons.AutoMirrored.Rounded.ArrowBack,
                        contentDescription = "Previous",
                        modifier = Modifier.size(18.dp)
                    )
                    Spacer(modifier = Modifier.width(6.dp))
                    Text(
                        if (language == BibleLanguage.URDU) "پچھلا" else "Previous",
                        style = MaterialTheme.typography.labelLarge
                    )
                }

                // Chapter Info Badge
                Surface(
                    shape = RoundedCornerShape(12.dp),
                    color = MaterialTheme.colorScheme.primaryContainer,
                    modifier = Modifier.padding(horizontal = 12.dp)
                ) {
                    CompositionLocalProvider(
                        LocalLayoutDirection provides if (isUrdu) LayoutDirection.Rtl else LayoutDirection.Ltr
                    ) {
                        Text(
                            text = "$chapter / ${book.chapters}",
                            style = MaterialTheme.typography.labelLarge,
                            color = MaterialTheme.colorScheme.onPrimaryContainer,
                            fontWeight = FontWeight.Bold,
                            modifier = Modifier.padding(horizontal = 16.dp, vertical = 10.dp)
                        )
                    }
                }

                // Next Chapter Button
                Button(
                    onClick = onNextChapter,
                    enabled = chapter < book.chapters,
                    shape = RoundedCornerShape(12.dp),
                    modifier = Modifier.weight(1f)
                ) {
                    Text(
                        if (language == BibleLanguage.URDU) "اگلا" else "Next",
                        style = MaterialTheme.typography.labelLarge
                    )
                    Spacer(modifier = Modifier.width(6.dp))
                    Icon(
                        Icons.AutoMirrored.Rounded.ArrowForward,
                        contentDescription = "Next",
                        modifier = Modifier.size(18.dp)
                    )
                }
            }
        }

        // Scroll to top FAB
        if (showScrollToTop.value) {
            SmallFloatingActionButton(
                onClick = {
                    coroutineScope.launch {
                        listState.animateScrollToItem(0)
                    }
                },
                modifier = Modifier
                    .align(Alignment.BottomEnd)
                    .padding(end = 16.dp, bottom = 90.dp),
                containerColor = MaterialTheme.colorScheme.tertiaryContainer,
                contentColor = MaterialTheme.colorScheme.onTertiaryContainer
            ) {
                Icon(
                    Icons.Rounded.KeyboardArrowUp,
                    contentDescription = if (isUrdu) "اوپر جائیں" else "Scroll to top"
                )
            }
        }
    }
}

// Google Fonts Provider
val fontProvider = GoogleFont.Provider(
    providerAuthority = "com.google.android.gms.fonts",
    providerPackage = "com.google.android.gms",
    certificates = R.array.com_google_android_gms_fonts_certs
)

val NotoNastaliqUrduFont = GoogleFont("Noto Nastaliq Urdu")
val NotoNastaliqUrdu = FontFamily(
    Font(googleFont = NotoNastaliqUrduFont, fontProvider = fontProvider)
)

data class SongItem(
    val id: Int,
    val title: String,
    val lyrics: String,
    val language: String,
    val category: String,
    val indexChar: String,
    val heading: String? = null,
    val isPunjabi: Boolean = false
)

fun isUrduText(text: String): Boolean = text.any { it.code in 0x0600..0x06FF }

// ============ SONG DOWNLOAD & CACHE SYSTEM ============

// Remote URLs - Your GitHub repository
object SongUrls {
    const val URDU_SONGS = "https://raw.githubusercontent.com/yoshiashaleem/CPA-Songs-Book/main/urdusongs.json"
    const val ENGLISH_SONGS = "https://raw.githubusercontent.com/yoshiashaleem/CPA-Songs-Book/main/englishsongs.json"
}

// Cache file names
private const val CACHE_URDU = "cached_urdu_songs.json"
private const val CACHE_ENGLISH = "cached_english_songs.json"

suspend fun loadSongsAsync(context: Context): List<SongItem> {
    return withContext(Dispatchers.IO) {
        // Try to download from server and cache
        val urduResult = downloadAndCacheSongs(context, SongUrls.URDU_SONGS, CACHE_URDU, isUrdu = true)
        val englishResult = downloadAndCacheSongs(context, SongUrls.ENGLISH_SONGS, CACHE_ENGLISH, isUrdu = false)

        android.util.Log.d("CPA_SONGS", "Urdu songs loaded: ${urduResult.first.size}, from: ${urduResult.second}")
        android.util.Log.d("CPA_SONGS", "English songs loaded: ${englishResult.first.size}, from: ${englishResult.second}")

        (urduResult.first + englishResult.first)
            .distinctBy { it.title }
            .sortedBy { it.title }
    }
}

private fun downloadAndCacheSongs(
    context: Context,
    remoteUrl: String,
    cacheFileName: String,
    isUrdu: Boolean
): Pair<List<SongItem>, String> {
    val cacheFile = java.io.File(context.filesDir, cacheFileName)

    // Try to download from server with proper connection
    val remoteJson = try {
        val url = java.net.URL(remoteUrl)
        val connection = url.openConnection() as java.net.HttpURLConnection
        connection.connectTimeout = 10000 // 10 seconds
        connection.readTimeout = 10000
        connection.requestMethod = "GET"
        connection.setRequestProperty("Accept", "application/json")
        connection.setRequestProperty("User-Agent", "CPA-Songs-App")

        val responseCode = connection.responseCode
        android.util.Log.d("CPA_SONGS", "URL: $remoteUrl, Response: $responseCode")

        if (responseCode == 200) {
            connection.inputStream.bufferedReader().use { it.readText() }
        } else {
            android.util.Log.e("CPA_SONGS", "HTTP Error: $responseCode")
            null
        }
    } catch (e: Exception) {
        android.util.Log.e("CPA_SONGS", "Failed to download: ${e.message}")
        null
    }

    // If download successful, parse and validate before caching
    if (remoteJson != null && remoteJson.isNotEmpty()) {
        val remoteSongs = parseJsonToSongs(remoteJson, isUrdu)

        // Only save to cache if we got valid songs (protection against empty/deleted data)
        if (remoteSongs.isNotEmpty()) {
            try {
                cacheFile.writeText(remoteJson)
                android.util.Log.d("CPA_SONGS", "Saved ${remoteSongs.size} songs to cache: $cacheFileName")
            } catch (e: Exception) {
                android.util.Log.e("CPA_SONGS", "Failed to cache: ${e.message}")
            }
            return Pair(remoteSongs, "REMOTE")
        } else {
            android.util.Log.w("CPA_SONGS", "Remote returned empty/invalid data, keeping old cache")
        }
    }

    // If download failed or empty, try to load from cache
    val cachedJson = try {
        if (cacheFile.exists()) {
            android.util.Log.d("CPA_SONGS", "Loading from cache: $cacheFileName")
            cacheFile.readText()
        } else null
    } catch (e: Exception) {
        null
    }

    if (cachedJson != null && cachedJson.isNotEmpty()) {
        val cachedSongs = parseJsonToSongs(cachedJson, isUrdu)
        if (cachedSongs.isNotEmpty()) {
            return Pair(cachedSongs, "CACHE")
        }
    }

    // Last resort: load from bundled assets
    android.util.Log.d("CPA_SONGS", "Loading from assets")
    val assetJson = try {
        val assetName = if (isUrdu) "urdusongs.json" else "englishsongs.json"
        context.assets.open(assetName).bufferedReader().use { it.readText() }
    } catch (e: Exception) {
        return Pair(emptyList(), "NONE")
    }

    return Pair(parseJsonToSongs(assetJson, isUrdu), "ASSETS")
}

private fun parseJsonToSongs(jsonString: String, isUrdu: Boolean): List<SongItem> {
    return try {
        val listType = object : TypeToken<List<Map<String, String>>>() {}.type
        val rawSongs: List<Map<String, String>> = Gson().fromJson(jsonString, listType) ?: emptyList()
        rawSongs.mapIndexed { index, map ->
            val lyrics = map["content"] ?: ""
            val categoryRaw = map["category"] ?: "Song"
            val language = map["language"] ?: if (isUrduText(lyrics)) "Urdu" else "English"
            val isPsalm = categoryRaw.contains("psalms", ignoreCase = true) || categoryRaw.equals("Psalm", ignoreCase = true)

            SongItem(
                id = (if (isUrdu) 0 else 5000) + index,
                title = map["title"] ?: "",
                lyrics = lyrics,
                language = language,
                category = if (isPsalm) "Psalm" else "Song",
                indexChar = map["section_label"] ?: (map["title"]?.firstOrNull()?.toString()?.uppercase() ?: "#"),
                heading = map["heading"],
                isPunjabi = isUrdu && (isPsalm || lyrics.contains("ساڈا") || lyrics.contains("سانوں") || lyrics.contains("تینوں") || lyrics.contains("اوہ"))
            )
        }
    } catch (e: Exception) {
        emptyList()
    }
}

@OptIn(ExperimentalMaterial3Api::class)
@Composable
fun SongBookApp(onBack: () -> Unit = {}) {
    val context = LocalContext.current
    var selectedSong by remember { mutableStateOf<SongItem?>(null) }
    var selectedLetter by remember { mutableStateOf<String?>(null) }
    var selectedTab by remember { mutableIntStateOf(2) }
    var searchQuery by remember { mutableStateOf("") }
    var isSearching by remember { mutableStateOf(false) }

    var allSongs by remember { mutableStateOf<List<SongItem>>(emptyList()) }
    var isLoading by remember { mutableStateOf(true) }

    LaunchedEffect(Unit) {
        allSongs = loadSongsAsync(context)
        isLoading = false
    }

    val filteredSongs = allSongs.filter { song ->
        val matchesTab = when (selectedTab) {
            1 -> song.language.equals("English", ignoreCase = true)
            2 -> song.language.equals("Urdu", ignoreCase = true) && song.category == "Song"
            3 -> song.language.equals("Urdu", ignoreCase = true) && song.category == "Psalm"
            else -> true
        }
        val matchesSearch = searchQuery.isEmpty() ||
                          song.title.contains(searchQuery, ignoreCase = true) || 
                          (song.heading?.contains(searchQuery, ignoreCase = true) ?: false) ||
                          song.lyrics.contains(searchQuery, ignoreCase = true)
        matchesTab && matchesSearch
    }

    // Handle back navigation
    val showBackToHome = selectedSong == null && selectedLetter == null && !isSearching

    BackHandler(enabled = selectedSong != null || selectedLetter != null || isSearching) {
        when {
            selectedSong != null -> selectedSong = null
            selectedLetter != null -> selectedLetter = null
            isSearching -> { isSearching = false; searchQuery = "" }
        }
    }

    Scaffold(
        containerColor = MaterialTheme.colorScheme.background,
        topBar = {
            Column(
                modifier = Modifier
                    .background(MaterialTheme.colorScheme.background)
                    .statusBarsPadding()
            ) {
                // Top App Bar
                TopAppBar(
                    title = {
                        when {
                            selectedSong != null -> { /* Empty for detail view */ }
                            isSearching -> {
                                SearchBar(
                                    query = searchQuery,
                                    onQueryChange = { searchQuery = it },
                                    onClear = { searchQuery = "" }
                                )
                            }
                            selectedLetter != null -> {
                                val isUrdu = isUrduText(selectedLetter!!)
                                Text(
                                    text = selectedLetter!!,
                                    style = if (isUrdu) {
                                        MaterialTheme.typography.headlineMedium.copy(
                                            fontFamily = NotoNastaliqUrdu,
                                            fontWeight = FontWeight.Bold
                                        )
                                    } else {
                                        MaterialTheme.typography.headlineMedium.copy(fontWeight = FontWeight.Bold)
                                    },
                                    color = MaterialTheme.colorScheme.primary
                                )
                            }
                            else -> {
                                Column {
                                    Text(
                                        "CPA",
                                        style = MaterialTheme.typography.labelMedium,
                                        color = MaterialTheme.colorScheme.primary,
                                        letterSpacing = 3.sp
                                    )
                                    Text(
                                        "Songs Book",
                                        style = MaterialTheme.typography.titleLarge.copy(
                                            fontWeight = FontWeight.SemiBold
                                        ),
                                        color = MaterialTheme.colorScheme.onBackground
                                    )
                                }
                            }
                        }
                    },
                    navigationIcon = {
                        // Always show back arrow (to go back to home or previous screen)
                        IconButton(
                            onClick = {
                                when {
                                    selectedSong != null -> selectedSong = null
                                    selectedLetter != null -> selectedLetter = null
                                    isSearching -> { isSearching = false; searchQuery = "" }
                                    else -> onBack()
                                }
                            }
                        ) {
                            Icon(
                                Icons.AutoMirrored.Rounded.ArrowBack,
                                contentDescription = "Back",
                                tint = MaterialTheme.colorScheme.onBackground
                            )
                        }
                    },
                    actions = {
                        if (selectedSong == null && !isSearching) {
                            IconButton(onClick = { isSearching = true }) {
                                Icon(
                                    Icons.Rounded.Search,
                                    contentDescription = "Search",
                                    tint = MaterialTheme.colorScheme.onBackground
                                )
                            }
                        }
                    },
                    colors = TopAppBarDefaults.topAppBarColors(
                        containerColor = Color.Transparent
                    )
                )

                // Category Tabs
                if (!isSearching && selectedSong == null && selectedLetter == null) {
                    CategoryTabs(
                        selectedTab = selectedTab,
                        onTabSelected = { selectedTab = it }
                    )
                }
            }
        }
    ) { innerPadding ->
        Box(
            modifier = Modifier
                .padding(innerPadding)
                .fillMaxSize()
        ) {
            val songPageKey = when {
                selectedSong != null -> 3
                isLoading -> -1
                selectedLetter != null || isSearching -> 2
                else -> 1
            }

            AnimatedContent(
                targetState = songPageKey,
                transitionSpec = {
                    if (targetState > initialState) {
                        slideInHorizontally { it } togetherWith slideOutHorizontally { -it }
                    } else {
                        slideInHorizontally { -it } togetherWith slideOutHorizontally { it }
                    }
                },
                label = "songTransition"
            ) { page ->
                when (page) {
                    3 -> {
                        val song = selectedSong ?: return@AnimatedContent
                        SongDetailScreen(song = song)
                    }
                    -1 -> LoadingScreen()
                    2 -> {
                        val displayList = if (isSearching) filteredSongs
                                         else filteredSongs.filter { it.indexChar == selectedLetter }
                        SongListScreen(
                            songs = displayList,
                            onSongClick = { selectedSong = it }
                        )
                    }
                    else -> SongIndexScreen(
                        grouped = filteredSongs.groupBy { it.indexChar }.toSortedMap(),
                        onLetterClick = { selectedLetter = it }
                    )
                }
            }
        }
    }
}

@Composable
fun SearchBar(
    query: String,
    onQueryChange: (String) -> Unit,
    onClear: () -> Unit
) {
    OutlinedTextField(
        value = query,
        onValueChange = onQueryChange,
        placeholder = {
            Text(
                "Search songs...",
                style = MaterialTheme.typography.bodyMedium,
                color = MaterialTheme.colorScheme.onSurfaceVariant.copy(alpha = 0.6f)
            )
        },
        modifier = Modifier
            .fillMaxWidth()
            .height(52.dp),
        shape = RoundedCornerShape(16.dp),
        colors = OutlinedTextFieldDefaults.colors(
            focusedContainerColor = MaterialTheme.colorScheme.surfaceVariant,
            unfocusedContainerColor = MaterialTheme.colorScheme.surfaceVariant,
            focusedBorderColor = MaterialTheme.colorScheme.primary.copy(alpha = 0.5f),
            unfocusedBorderColor = Color.Transparent,
            cursorColor = MaterialTheme.colorScheme.primary
        ),
        textStyle = MaterialTheme.typography.bodyMedium,
        trailingIcon = {
            if (query.isNotEmpty()) {
                IconButton(onClick = onClear) {
                    Icon(
                        Icons.Rounded.Close,
                        contentDescription = "Clear",
                        modifier = Modifier.size(20.dp),
                        tint = MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
            }
        },
        singleLine = true
    )
}

@Composable
fun CategoryTabs(
    selectedTab: Int,
    onTabSelected: (Int) -> Unit
) {
    val tabs = listOf("All", "English", "Geet", "Zaboor")

    ScrollableTabRow(
        selectedTabIndex = selectedTab,
        containerColor = Color.Transparent,
        contentColor = MaterialTheme.colorScheme.primary,
        edgePadding = 16.dp,
        divider = {},
        indicator = { tabPositions ->
            if (selectedTab < tabPositions.size) {
                val indicatorLeft by animateDpAsState(
                    targetValue = tabPositions[selectedTab].left,
                    animationSpec = spring(
                        dampingRatio = Spring.DampingRatioMediumBouncy,
                        stiffness = Spring.StiffnessMediumLow
                    ),
                    label = "indicatorLeft"
                )
                val indicatorWidth by animateDpAsState(
                    targetValue = tabPositions[selectedTab].width,
                    animationSpec = spring(
                        dampingRatio = Spring.DampingRatioMediumBouncy,
                        stiffness = Spring.StiffnessMediumLow
                    ),
                    label = "indicatorWidth"
                )

                Box(
                    Modifier
                        .fillMaxWidth()
                        .wrapContentSize(Alignment.BottomStart)
                        .offset(x = indicatorLeft)
                        .width(indicatorWidth)
                        .height(3.dp)
                        .padding(horizontal = 24.dp)
                        .clip(RoundedCornerShape(topStart = 3.dp, topEnd = 3.dp))
                        .background(MaterialTheme.colorScheme.primary)
                )
            }
        }
    ) {
        tabs.forEachIndexed { index, title ->
            val selected = selectedTab == index
            Tab(
                selected = selected,
                onClick = { onTabSelected(index) },
                text = {
                    Text(
                        title,
                        style = MaterialTheme.typography.labelLarge,
                        fontWeight = if (selected) FontWeight.Bold else FontWeight.Medium,
                        color = if (selected) MaterialTheme.colorScheme.primary 
                               else MaterialTheme.colorScheme.onSurfaceVariant
                    )
                }
            )
        }
    }
}

@Composable
fun LoadingScreen() {
    Box(
        modifier = Modifier.fillMaxSize(),
        contentAlignment = Alignment.Center
    ) {
        Column(horizontalAlignment = Alignment.CenterHorizontally) {
            CircularProgressIndicator(
                modifier = Modifier.size(48.dp),
                strokeWidth = 3.dp,
                color = MaterialTheme.colorScheme.primary,
                trackColor = MaterialTheme.colorScheme.surfaceVariant
            )
            Spacer(modifier = Modifier.height(16.dp))
            Text(
                "Loading songs...",
                style = MaterialTheme.typography.bodyMedium,
                color = MaterialTheme.colorScheme.onSurfaceVariant
            )
        }
    }
}

@Composable
fun SongIndexScreen(
    grouped: Map<String, List<SongItem>>,
    onLetterClick: (String) -> Unit
) {
    val keys = grouped.keys.toList()
    val isRtl = keys.any { isUrduText(it) }

    // Adaptive columns based on screen width
    val configuration = LocalConfiguration.current
    val columns = when {
        configuration.screenWidthDp >= 840 -> 6  // Large tablets / Chrome OS
        configuration.screenWidthDp >= 600 -> 4  // Small tablets
        else -> 3                                 // Phones
    }

    CompositionLocalProvider(LocalLayoutDirection provides if (isRtl) LayoutDirection.Rtl else LayoutDirection.Ltr) {
        LazyVerticalGrid(
            columns = GridCells.Fixed(columns),
            modifier = Modifier.fillMaxSize(),
            contentPadding = PaddingValues(20.dp),
            horizontalArrangement = Arrangement.spacedBy(12.dp),
            verticalArrangement = Arrangement.spacedBy(12.dp)
        ) {
            items(keys.size, key = { keys[it] }) { index ->
                val char = keys[index]
                AnimatedIndexCard(
                    char = char,
                    count = grouped[char]?.size ?: 0,
                    index = index,
                    onClick = { onLetterClick(char) }
                )
            }
        }
    }
}

@Composable
fun AnimatedIndexCard(
    char: String,
    count: Int,
    index: Int,
    onClick: () -> Unit
) {
    IndexCard(char = char, count = count, onClick = onClick)
}

@Composable
fun IndexCard(
    char: String,
    count: Int,
    onClick: () -> Unit
) {
    val isUrdu = isUrduText(char)

    Card(
        onClick = onClick,
        modifier = Modifier
            .aspectRatio(1f),
        shape = RoundedCornerShape(20.dp),
        colors = CardDefaults.cardColors(
            containerColor = MaterialTheme.colorScheme.surface
        ),
        elevation = CardDefaults.cardElevation(defaultElevation = 2.dp)
    ) {
        Box(
            modifier = Modifier.fillMaxSize(),
            contentAlignment = Alignment.Center
        ) {
            Column(
                horizontalAlignment = Alignment.CenterHorizontally,
                verticalArrangement = Arrangement.Center
            ) {
                Text(
                    text = char,
                    style = if (isUrdu) {
                        MaterialTheme.typography.headlineLarge.copy(
                            fontFamily = NotoNastaliqUrdu,
                            fontSize = 32.sp
                        )
                    } else {
                        MaterialTheme.typography.headlineLarge
                    },
                    color = MaterialTheme.colorScheme.primary
                )
                Spacer(modifier = Modifier.height(4.dp))
                Text(
                    text = "$count",
                    style = MaterialTheme.typography.labelSmall,
                    color = MaterialTheme.colorScheme.onSurfaceVariant
                )
            }
        }
    }
}

@Composable
fun SongListScreen(
    songs: List<SongItem>,
    onSongClick: (SongItem) -> Unit
) {
    if (songs.isEmpty()) {
        Box(
            modifier = Modifier.fillMaxSize(),
            contentAlignment = Alignment.Center
        ) {
            Column(horizontalAlignment = Alignment.CenterHorizontally) {
                Text(
                    "",
                    fontSize = 48.sp
                )
                Spacer(modifier = Modifier.height(16.dp))
                Text(
                    "No songs found",
                    style = MaterialTheme.typography.titleMedium,
                    color = MaterialTheme.colorScheme.onSurfaceVariant
                )
            }
        }
        return
    }

    LazyColumn(
        modifier = Modifier.fillMaxSize(),
        contentPadding = PaddingValues(vertical = 8.dp)
    ) {
        itemsIndexed(songs, key = { _, song -> song.id }) { index, song ->
            SongListItem(
                song = song,
                index = index,
                onClick = { onSongClick(song) }
            )
        }
    }
}

@Composable
fun SongListItem(
    song: SongItem,
    index: Int,
    onClick: () -> Unit
) {
    val isUrduTitle = isUrduText(song.title)
    val layoutDirection = if (isUrduTitle) LayoutDirection.Rtl else LayoutDirection.Ltr

    Card(
        onClick = onClick,
        modifier = Modifier
            .fillMaxWidth()
            .padding(horizontal = 16.dp, vertical = 6.dp),
        shape = RoundedCornerShape(16.dp),
        colors = CardDefaults.cardColors(
            containerColor = MaterialTheme.colorScheme.surface
        ),
        elevation = CardDefaults.cardElevation(defaultElevation = 1.dp)
    ) {
        CompositionLocalProvider(LocalLayoutDirection provides layoutDirection) {
            Row(
                modifier = Modifier
                    .fillMaxWidth()
                    .padding(16.dp),
                verticalAlignment = Alignment.CenterVertically
            ) {
                // Song Number Badge
                    Box(
                        modifier = Modifier
                            .size(44.dp)
                            .clip(CircleShape)
                            .background(MaterialTheme.colorScheme.primaryContainer),
                        contentAlignment = Alignment.Center
                    ) {
                        Text(
                            text = "${index + 1}",
                            style = MaterialTheme.typography.labelLarge,
                            color = Color.White,
                            fontWeight = FontWeight.Bold
                        )
                    }

                    Spacer(modifier = Modifier.width(16.dp))

                    Column(modifier = Modifier.weight(1f)) {
                        if (song.category == "Psalm" && song.heading != null) {
                            val isUrduHeading = isUrduText(song.heading)
                            Text(
                                text = song.heading,
                                style = if (isUrduHeading) {
                                    MaterialTheme.typography.labelSmall.copy(
                                        fontFamily = NotoNastaliqUrdu,
                                        fontSize = 12.sp
                                    )
                                } else {
                                    MaterialTheme.typography.labelSmall
                                },
                                color = MaterialTheme.colorScheme.primary.copy(alpha = 0.7f),
                                maxLines = 1,
                                overflow = TextOverflow.Ellipsis
                            )
                            Spacer(modifier = Modifier.height(2.dp))
                        }

                        Text(
                            text = song.title,
                            style = if (isUrduTitle) {
                                MaterialTheme.typography.titleMedium.copy(
                                    fontFamily = NotoNastaliqUrdu,
                                    fontSize = 18.sp,
                                    lineHeight = 28.sp
                                )
                            } else {
                                MaterialTheme.typography.titleMedium
                            },
                            color = MaterialTheme.colorScheme.onSurface,
                            maxLines = 2,
                            overflow = TextOverflow.Ellipsis
                        )

                        Spacer(modifier = Modifier.height(4.dp))

                        Row(verticalAlignment = Alignment.CenterVertically) {
                            CategoryChip(category = song.category)
                            Spacer(modifier = Modifier.width(8.dp))
                            Text(
                                text = song.language,
                                style = MaterialTheme.typography.labelSmall,
                                color = MaterialTheme.colorScheme.onSurfaceVariant
                            )
                        }
                    }
                }
            }
        }
    }

@Composable
fun CategoryChip(category: String) {
    Surface(
        shape = RoundedCornerShape(6.dp),
        color = if (category == "Psalm") 
                   MaterialTheme.colorScheme.tertiaryContainer 
               else MaterialTheme.colorScheme.secondaryContainer
    ) {
        Text(
            text = category,
            modifier = Modifier.padding(horizontal = 8.dp, vertical = 2.dp),
            style = MaterialTheme.typography.labelSmall,
            color = if (category == "Psalm")
                       MaterialTheme.colorScheme.onTertiaryContainer
                   else MaterialTheme.colorScheme.onSecondaryContainer
        )
    }
}

@Composable
fun SongDetailScreen(song: SongItem) {
    val isUrduTitle = isUrduText(song.title)
    val isUrduLyrics = isUrduText(song.lyrics)

    // Responsive padding for larger screens
    val configuration = LocalConfiguration.current
    val horizontalPadding = when {
        configuration.screenWidthDp >= 840 -> 120.dp  // Large tablets
        configuration.screenWidthDp >= 600 -> 60.dp   // Small tablets
        else -> 24.dp                                  // Phones
    }

    LazyColumn(
        modifier = Modifier.fillMaxSize(),
        contentPadding = PaddingValues(horizontal = horizontalPadding, vertical = 24.dp),
        horizontalAlignment = Alignment.CenterHorizontally
    ) {
        item {
            Column(horizontalAlignment = Alignment.CenterHorizontally) {
                // Category Badge
                Surface(
                    shape = RoundedCornerShape(20.dp),
                    color = MaterialTheme.colorScheme.primaryContainer
                ) {
                        Text(
                            text = song.category.uppercase(),
                            modifier = Modifier.padding(horizontal = 16.dp, vertical = 6.dp),
                            style = MaterialTheme.typography.labelMedium,
                            color = MaterialTheme.colorScheme.onPrimaryContainer,
                            letterSpacing = 2.sp
                        )
                    }

                    Spacer(modifier = Modifier.height(16.dp))

                    // Heading (for Psalms)
                    if (song.heading != null) {
                        val isUrduHeading = isUrduText(song.heading)
                        Text(
                            text = song.heading,
                            style = if (isUrduHeading) {
                                MaterialTheme.typography.titleMedium.copy(
                                    fontFamily = NotoNastaliqUrdu,
                                    fontSize = 16.sp
                                )
                            } else {
                                MaterialTheme.typography.titleMedium
                            },
                            color = MaterialTheme.colorScheme.primary,
                            textAlign = TextAlign.Center
                        )
                        Spacer(modifier = Modifier.height(8.dp))
                    }

                    // Title
                    Text(
                        text = song.title,
                        style = if (isUrduTitle) {
                            MaterialTheme.typography.headlineMedium.copy(
                                fontFamily = NotoNastaliqUrdu,
                                fontSize = 28.sp,
                                lineHeight = 44.sp,
                                fontWeight = FontWeight.Bold
                            )
                        } else {
                            MaterialTheme.typography.headlineMedium.copy(
                                fontWeight = FontWeight.Bold
                            )
                        },
                        textAlign = TextAlign.Center,
                        color = MaterialTheme.colorScheme.onBackground
                    )

                    Spacer(modifier = Modifier.height(24.dp))

                    // Decorative Divider
                    Row(
                        verticalAlignment = Alignment.CenterVertically,
                        horizontalArrangement = Arrangement.Center,
                        modifier = Modifier.fillMaxWidth()
                    ) {
                        Box(
                            modifier = Modifier
                                .width(40.dp)
                                .height(1.dp)
                                .background(
                                    brush = Brush.horizontalGradient(
                                        colors = listOf(
                                            Color.Transparent,
                                            MaterialTheme.colorScheme.primary.copy(alpha = 0.5f)
                                        )
                                    )
                                )
                        )
                        Spacer(modifier = Modifier.width(8.dp))
                        Box(
                            modifier = Modifier
                                .size(8.dp)
                                .clip(CircleShape)
                                .background(MaterialTheme.colorScheme.primary)
                        )
                        Spacer(modifier = Modifier.width(8.dp))
                        Box(
                            modifier = Modifier
                                .width(40.dp)
                                .height(1.dp)
                                .background(
                                    brush = Brush.horizontalGradient(
                                        colors = listOf(
                                            MaterialTheme.colorScheme.primary.copy(alpha = 0.5f),
                                            Color.Transparent
                                        )
                                    )
                                )
                        )
                    }

                    Spacer(modifier = Modifier.height(32.dp))

                    // Lyrics
                    Text(
                        text = song.lyrics,
                        style = if (isUrduLyrics) {
                            MaterialTheme.typography.bodyLarge.copy(
                                fontFamily = NotoNastaliqUrdu,
                                fontSize = 22.sp,
                                lineHeight = 52.sp
                            )
                        } else {
                            MaterialTheme.typography.bodyLarge.copy(
                                lineHeight = 32.sp
                            )
                        },
                        textAlign = TextAlign.Center,
                        color = MaterialTheme.colorScheme.onBackground
                    )

                    Spacer(modifier = Modifier.height(80.dp))
                }
            }
        }
    }

// Extension for tab indicator offset
@Composable
fun Modifier.tabIndicatorOffset(
    currentTabPosition: TabPosition
): Modifier = this.then(
    Modifier
        .fillMaxWidth()
        .wrapContentSize(Alignment.BottomStart)
        .offset(x = currentTabPosition.left)
        .width(currentTabPosition.width)
)
